        storageObjects = data.objects || [];
        renderStorageList();
    } catch(e) { container.innerHTML = `<div style="color:var(--danger); padding:20px;">${e.message}</div>`; }
}

ops.replace_with:
async function fetchStorageObjects(isAppend = false) {
    if (isPerformingAction) return;
    const container = document.getElementById('storage-content');
    const bread = document.getElementById('storage-breadcrumbs');
    const sortBy = document.getElementById('storage-sort-by')?.value || 'name';

    if (!isAppend) {
        storageOffset = 0;
        storageHasMore = true;
        storageObjects = [];
        container.innerHTML = '<div style="padding:40px; text-align:center; color:var(--ai-accent);">Reading Objects...</div>';
    }

    isPerformingAction = true;

    document.getElementById('storage-title').innerText = storageCurrentBucket;
    bread.style.display = 'block';
    bread.innerHTML = `<span onclick="fetchBuckets()" style="cursor:pointer; color:var(--primary);">buckets</span> / ` + 
        storageCurrentPath.map((p, i) => `<span onclick="navigateToStorageDepth(${i})" style="cursor:pointer; color:var(--primary);">${p}</span>`).join(' / ');

    document.getElementById('storage-controls').style.display = 'flex';
    document.getElementById('btn-storage-upload').style.display = 'block';
    document.getElementById('storage-footer').style.display = 'flex';

    try {
        const path = storageCurrentPath.join('/');
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ 
                action: 'list_storage_objects', 
                bucket: storageCurrentBucket, 
                path: path, 
                sort_by: sortBy,
                sort_order: storageSortOrder,
                offset: storageOffset
            })
        });
        const data = await res.json();
        const fetched = data.objects || [];

        storageObjects = isAppend ? storageObjects.concat(fetched) : fetched;
        storageOffset += 100;
        storageHasMore = fetched.length === 100;

        renderStorageList();

        // Attach Scroll Listener for infinite scroll
        container.onscroll = () => {
            if (container.scrollTop + container.clientHeight >= container.scrollHeight - 50) {
                if (storageHasMore && !isPerformingAction) fetchStorageObjects(true);
            }
        };

    } catch(e) {
        if (!isAppend) container.innerHTML = `<div style="color:var(--danger); padding:20px;">${e.message}</div>`;
    } finally {
        isPerformingAction = false;
    }
}

