2271 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2272 |     function applyLocalPatch(content, ops) {
2273 |         let lines = content.split('\n');
2274 |         let logs = [];
2275 |         let success = true;
2276 | 
2277 |         if (typeof ops === 'string') {
2278 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2279 |         }
2280 | 
2281 |         ops.forEach(op => {
2282 |             if (op.action === 'comment') return;
2283 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2284 |             
2285 |             if (op.action === 'replace_block') {
2286 |                 // Strategy 1: Exact String Match (Fastest)
2287 |                 const currentStr = lines.join('\n');
2288 |                 if (currentStr.includes(op.find_block)) {
2289 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2290 |                     logs.push('Exact match applied');
2291 |                     return;
2292 |                 }
2293 | 
2294 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2295 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2296 |                 if (searchLines.length === 0) return;
2297 | 
2298 |                 let matchStart = -1;
2299 |                 let matchEnd = -1;
2300 | 
2301 |                 // Scan file lines
2302 |                 for (let i = 0; i < lines.length; i++) {
2303 |                     // If first line matches (ignoring whitespace)
2304 |                     if (lines[i].trim() === searchLines[0]) {
2305 |                         // Check subsequent lines
2306 |                         let allMatch = true;
2307 |                         let fileOffset = 0;
2308 |                         let searchOffset = 1;
2309 |                         
2310 |                         while (searchOffset < searchLines.length) {
2311 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2312 |                             const nextFile = lines[i + fileOffset + 1].trim();
2313 |                             // Skip empty lines in file if they aren't in search block
2314 |                             if (nextFile === '') {
2315 |                                 fileOffset++;
2316 |                                 continue;
2317 |                             }
2318 |                             if (nextFile !== searchLines[searchOffset]) {
2319 |                                 allMatch = false;
2320 |                                 break;
2321 |                             }
2322 |                             fileOffset++;
2323 |                             searchOffset++;
2324 |                         }
2325 | 
2326 |                         if (allMatch) {
2327 |                             matchStart = i;
2328 |                             matchEnd = i + fileOffset;
2329 |                             break;
2330 |                         }
2331 |                     }
2332 |                 }
2333 | 
2334 |                 if (matchStart !== -1) {
2335 |                     // Replace the range of lines
2336 |                     const replacement = op.replace_with.split('\n');
2337 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2338 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2339 |                 } else {
2340 |                     success = false;
2341 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2342 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2343 |                 }
2344 |             }
2345 |         });
2346 |         return { content: lines.join('\n'), success, logs };
2347 |     }
