5178 |     // --- GENERIC UI ---
5179 |     function formatBytes(bytes) {
5180 |         if (!bytes) return '0 B';
5181 |         const k = 1024;
5182 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5183 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5184 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5185 |     }
