5187 |     function timeAgo(dateString) {
5188 |         const date = new Date(dateString);
5189 |         const now = new Date();
5190 |         const seconds = Math.floor((now - date) / 1000);
5191 |         if (seconds < 10) return 'just now';
5192 |         if (seconds < 60) return seconds + 's ago';
5193 |         const minutes = Math.floor(seconds / 60);
5194 |         if (minutes < 60) return minutes + 'm ago';
5195 |         const hours = Math.floor(minutes / 60);
5196 |         if (hours < 24) return hours + 'h ago';
5197 |         return date.toLocaleDateString();
5198 |     }
