5414 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5415 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5416 |         
5417 |         const navItems = document.querySelectorAll('.nav-item');
5418 |         switchTab(tabId, navItems[navIndex]);
5419 | 
5420 |         const scrollContainer = document.querySelector('.main-view');
5421 |         let retryCount = 0;
5422 |         const MAX_RETRIES = 5;
5423 | 
5424 |         const attemptNavigation = async () => {
5425 |             const element = document.querySelector(selector);
5426 |             
5427 |             if (element) {
5428 |                 console.log("[DeepJump] Element found. Scrolling...");
5429 |                 
5430 |                 // Wait for any tab transition animations
5431 |                 await new Promise(r => setTimeout(r, 300));
5432 | 
5433 |                 let offsetTop = 0;
5434 |                 let curr = element;
5435 |                 while (curr && curr !== scrollContainer) {
5436 |                     offsetTop += curr.offsetTop;
5437 |                     curr = curr.offsetParent;
5438 |                 }
5439 | 
5440 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5441 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5442 | 
5443 |                 // Visual Highlight
5444 |                 element.style.transition = 'all 0.5s ease';
5445 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5446 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5447 |                 setTimeout(() => {
5448 |                     element.style.backgroundColor = '';
5449 |                     element.style.boxShadow = '';
5450 |                 }, 3000);
5451 |                 
5452 |                 console.groupEnd();
5453 |                 return true;
5454 |             }
5455 | 
5456 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5457 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5458 |                 retryCount++;
5459 |                 showGlobalToast("🔍 Searching deeper...");
5460 |                 
5461 |                 await loadMoreFn(); 
5462 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5463 |                 return attemptNavigation();
5464 |             }
5465 | 
5466 |             console.error("[DeepJump] Failed: Element not found after retries.");
5467 |             showGlobalToast("Entry not found in recent history.", true);
5468 |             console.groupEnd();
5469 |             return false;
5470 |         };
5471 | 
5472 |         setTimeout(attemptNavigation, 100);
5473 |     }
