7936 |     function extractTableNames(sql) {
7937 |         if (!sql) return [];
7938 |         const tables = [];
7939 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7940 |         
7941 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7942 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7943 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7944 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7945 | 
7946 |         let match;
7947 |         while ((match = fromRegex.exec(sql)) !== null) {
7948 |             const name = match[1];
7949 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7950 |                 tables.push(name);
7951 |             }
7952 |         }
7953 |         
7954 |         while ((match = metaRegex.exec(sql)) !== null) {
7955 |             const name = match[1];
7956 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7957 |                 tables.push(name);
7958 |             }
7959 |         }
7960 | 
7961 |         return tables;
7962 |     }
7963 | 
7964 |     function convertToCSV(resultObj) {
7965 |         const data = resultObj.data || [];
7966 |         if (!data.length) return '';
7967 |         
7968 |         const tables = extractTableNames(resultObj.sql);
7969 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7970 | 
7971 |         const headers = Object.keys(data[0]);
7972 |         const rows = data.map(row => 
7973 |             headers.map(header => {
7974 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7975 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7976 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7977 |             }).join(',')
7978 |         );
7979 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7980 |     }
