function updateStorageSelectionCount() {
    const checks = Array.from(document.querySelectorAll('.storage-check'));
    const checkedCount = checks.filter(c => c.checked).length;

    document.getElementById('storage-selection-count').innerText = `${checkedCount} selected`;

    // Sync Master Checkbox State
    const master = document.getElementById('storage-master-check');
    if (master && checks.length > 0) {
        master.checked = checkedCount === checks.length;
        master.indeterminate = checkedCount > 0 && checkedCount < checks.length;
    }

    const totalEl = document.getElementById('storage-total-count');
    if (totalEl) {
        totalEl.innerText = `${storageObjects.length}${storageHasMore ? '+' : ''} items`;
    }
}

